const OIDC_REDIRECT_URI = process.env.OIDC_REDIRECT_URI || 'http://localhost:3000/callback';
const OIDC_AUTHORIZATION_ENDPOINT = process.env.OIDC_AUTHORIZATION_ENDPOINT || `${OIDC_ISSUER}/authorize`;
const OIDC_TOKEN_ENDPOINT = process.env.OIDC_TOKEN_ENDPOINT || `${OIDC_ISSUER}/token`;

